`celldefine
module AC1CINV2_12TR40 ( CO, A, B, CIN); 
input A, B, CIN;
output CO;

	and SMC_I0( CO_row1, A, B ); 
	not SMC_I1( CIN_inv, CIN ); 
	and SMC_I2( CO_row2, CIN_inv, A ); 
	and SMC_I3( CO_row3, CIN_inv, B ); 
	or SMC_I4( CO, CO_row1, CO_row2, CO_row3 ); 

   `ifdef functional  //  functional //

   `else




   specify

	if(B===1'b0 && CIN===1'b0)
	// arc A --> CO
	 (A => CO) = (1.0,1.0);

	if(B===1'b1 && CIN===1'b1)
	// arc A --> CO
	 (A => CO) = (1.0,1.0);

	if(A===1'b0 && CIN===1'b0)
	// arc B --> CO
	 (B => CO) = (1.0,1.0);

	if(A===1'b1 && CIN===1'b1)
	// arc B --> CO
	 (B => CO) = (1.0,1.0);

	if(A===1'b0 && B===1'b1)
	// arc CIN --> CO
	 (CIN => CO) = (1.0,1.0);

	if(A===1'b1 && B===1'b0)
	// arc CIN --> CO
	 (CIN => CO) = (1.0,1.0);

   endspecify

  `endif // functional //

endmodule
`endcelldefine
